interface EQ {
  stem: string;
  options: string[];
  correctAnswer: number;
  rationale: string;
  learningObjective: string;
  blueprintCategory: string;
  subtopic: string;
  difficulty: number;
  cognitiveLevel: string;
  questionType: "multiple-choice" | "image-interpretation" | "calculation" | "clinical-case";
  scenario?: string;
  exhibitData?: any;
  exam: string;
  regionScope: "US" | "CAN" | "BOTH";
}

export function getBatch46(): EQ[] {
  return [
    { stem: "In the evaluation of aortic stenosis, the peak aortic jet velocity should be obtained from:", options: ["Only the apical window", "Multiple windows (apical, right parasternal, suprasternal, subcostal) and the highest velocity recorded should be used", "Only the PLAX view", "Only the subcostal view"], correctAnswer: 1, rationale: "AS peak velocity varies significantly by window. The right parasternal often yields the highest velocity. All available windows should be checked and the highest peak velocity used for grading. Underestimation from a single window may lead to undergrading of AS severity.", learningObjective: "Describe multi-window approach for AS velocity", blueprintCategory: "Hemodynamic Measurements", subtopic: "Hemodynamic Calculations", difficulty: 2, cognitiveLevel: "recall", questionType: "multiple-choice", exam: "RDCS-AE", regionScope: "BOTH" },
    { stem: "The mitral valve commissural fusion in rheumatic disease is best assessed in:", options: ["The A4C view", "The PSAX at the MV level, which shows the commissures directly", "The PLAX view only", "The subcostal view only"], correctAnswer: 1, rationale: "The PSAX at the MV level directly visualizes both the anterolateral and posteromedial commissures, allowing assessment of commissural fusion extent and symmetry. This is important for Wilkins scoring and determining suitability for balloon mitral valvuloplasty.", learningObjective: "Identify the view for commissural fusion assessment", blueprintCategory: "Pathology Recognition", subtopic: "Valvular Disease Assessment", difficulty: 3, cognitiveLevel: "recall", questionType: "multiple-choice", exam: "RDCS-AE", regionScope: "BOTH" },
    { stem: "An echo shows a calcified mass at the base of the posterior mitral leaflet. This is most likely:", options: ["Vegetation", "Caseous calcification of the mitral annulus (a variant of MAC appearing as an echodense mass with echolucent center)", "Myxoma", "Papillary fibroelastoma"], correctAnswer: 1, rationale: "Caseous calcification of the mitral annulus: a variant of MAC appearing as a round, echodense mass with a central echolucent area (caseous/liquefied center). Located at the posterior mitral annulus. It can mimic abscess, tumor, or vegetation. CT confirms the calcific nature.", learningObjective: "Identify caseous calcification of mitral annulus", blueprintCategory: "Pathology Recognition", subtopic: "Cardiac Masses", difficulty: 4, cognitiveLevel: "recall", questionType: "multiple-choice", exam: "RDCS-AE", regionScope: "BOTH" },
    { stem: "The PSAX view at the mitral valve level shows the mitral valve opening as a:", options: ["Circular orifice", "Fish-mouth appearance with anterior and posterior leaflet motion", "Linear structure", "Y-shaped structure"], correctAnswer: 1, rationale: "At the MV level, the PSAX shows the mitral orifice opening in diastole with a characteristic fish-mouth appearance. The anterior and posterior leaflets open and close symmetrically. This view is used for planimetry of the MVA in mitral stenosis.", learningObjective: "Describe MV appearance in PSAX", blueprintCategory: "Anatomy/Physiology", subtopic: "Echo Imaging Views", difficulty: 1, cognitiveLevel: "recall", questionType: "multiple-choice", exam: "RDCS-AE", regionScope: "BOTH" },
    { stem: "Diastolic MR (mitral regurgitation in diastole) can occur with:", options: ["Normal AV function", "Severe aortic regurgitation, where the elevated LVEDP exceeds LA pressure in late diastole, causing the mitral valve to close prematurely and even reopen with backward flow", "Only during exercise", "Only with mitral stenosis"], correctAnswer: 1, rationale: "Diastolic MR: in acute severe AR, LVEDP rises rapidly and may exceed LA pressure before the next systole, causing premature mitral valve closure and diastolic MR. This is a sign of hemodynamic compromise and indicates need for urgent surgery. Also seen in complete heart block and acute severe MR.", learningObjective: "Explain diastolic MR mechanism", blueprintCategory: "Pathology Recognition", subtopic: "Valvular Disease Assessment", difficulty: 5, cognitiveLevel: "analysis", questionType: "multiple-choice", exam: "RDCS-AE", regionScope: "BOTH" },
    { stem: "The RV free wall longitudinal strain is measured using:", options: ["M-mode", "Speckle tracking applied to the RV free wall in the A4C view; normal ≥ -20% (more negative = better)", "CW Doppler", "3D volumetric analysis"], correctAnswer: 1, rationale: "RV free wall longitudinal strain: measured by speckle tracking in the A4C view, including the basal, mid, and apical segments of the RV free wall. Normal: ≤ -20% (more negative values = better function). Values less negative than -20% indicate RV dysfunction. It is a sensitive early marker of RV impairment.", learningObjective: "Describe RV free wall strain measurement", blueprintCategory: "Hemodynamic Measurements", subtopic: "RV Function Assessment", difficulty: 3, cognitiveLevel: "recall", questionType: "multiple-choice", exam: "RDCS-AE", regionScope: "BOTH" },
    { stem: "In CSCT practice, the echo assessment of a patient post-CABG should evaluate:", options: ["Only graft patency", "LV/RV function, new wall motion abnormalities, valve function (especially MR), pericardial effusion, and any complications (tamponade, graft failure)", "Only pericardial effusion", "Only EF"], correctAnswer: 1, rationale: "Post-CABG echo: LV function and wall motion (new or persistent abnormalities), valve function (MR may improve or worsen), pericardial effusion (common early post-op), RV function, and complications (tamponade, graft failure manifesting as new wall motion abnormalities in the grafted territory).", learningObjective: "Describe post-CABG echo assessment", blueprintCategory: "Pathology Recognition", subtopic: "Ischemic Heart Disease", difficulty: 3, cognitiveLevel: "recall", questionType: "multiple-choice", exam: "CSCT-CARDIAC", regionScope: "CAN" },
    { stem: "The ventricular torsion (twist) mechanism in the LV involves:", options: ["Only longitudinal shortening", "Counterclockwise rotation of the apex and clockwise rotation of the base during systole, creating a wringing motion that contributes to ejection", "Random motion", "Only radial thickening"], correctAnswer: 1, rationale: "LV torsion: the apex rotates counterclockwise and the base rotates clockwise during systole (viewed from the apex). This wringing motion enhances ejection efficiency. Diastolic untwist is rapid and contributes to early diastolic suction filling. Impaired torsion is an early sign of myocardial disease.", learningObjective: "Describe LV torsion mechanics", blueprintCategory: "Anatomy/Physiology", subtopic: "Cardiac Physiology", difficulty: 4, cognitiveLevel: "comprehension", questionType: "multiple-choice", exam: "RDCS-AE", regionScope: "BOTH" },
    { stem: "The coronary flow reserve (CFR) measured by echo assesses:", options: ["Coronary anatomy", "The ratio of hyperemic to resting coronary flow velocity in the LAD; CFR <2.0 suggests significant coronary stenosis or microvascular dysfunction", "Valve function", "Myocardial strain"], correctAnswer: 1, rationale: "CFR = hyperemic peak diastolic velocity / resting peak diastolic velocity in the LAD (usually measured with adenosine or dipyridamole). CFR <2.0 suggests flow-limiting epicardial stenosis or microvascular disease. Non-invasive CFR by echo has good correlation with invasive measurements.", learningObjective: "Describe coronary flow reserve measurement", blueprintCategory: "Hemodynamic Measurements", subtopic: "Advanced Echo Techniques", difficulty: 5, cognitiveLevel: "comprehension", questionType: "multiple-choice", exam: "RDCS-AE", regionScope: "BOTH" },
    { stem: "The normal number of standard TTE views in a comprehensive study per ASE guidelines is approximately:", options: ["5 views", "10 views", "20+ standard views organized by acoustic window", "3 views"], correctAnswer: 2, rationale: "A comprehensive TTE includes 20+ standard views: parasternal (PLAX, PSAX at multiple levels, RV inflow/outflow), apical (A4C, A2C, A3C, A5C), subcostal (4-chamber, IVC, short-axis), and suprasternal. Additional views are added based on clinical indication.", learningObjective: "State the number of standard TTE views", blueprintCategory: "Anatomy/Physiology", subtopic: "Echo Imaging Views", difficulty: 1, cognitiveLevel: "recall", questionType: "multiple-choice", exam: "RDCS-AE", regionScope: "BOTH" },
    { stem: "Mitral valve tenting height is measured in functional MR to assess:", options: ["Valve area", "The degree of leaflet tethering from LV remodeling; tenting height >10 mm and tenting area >2.5 cm² predict persistent MR after annuloplasty alone", "Valve thickness", "Annular velocity"], correctAnswer: 1, rationale: "Tenting height: distance from the mitral annular plane to the leaflet coaptation point. In functional MR, LV dilation displaces the papillary muscles, tethering the leaflets below the annular plane. Tenting height >10 mm predicts poor surgical repair outcome with annuloplasty alone.", learningObjective: "Interpret mitral valve tenting measurements", blueprintCategory: "Pathology Recognition", subtopic: "Valvular Disease Assessment", difficulty: 4, cognitiveLevel: "application", questionType: "multiple-choice", exam: "RDCS-AE", regionScope: "BOTH" },
    { stem: "The echo Doppler finding of a 'to-and-fro' pattern in the LVOT is seen with:", options: ["Normal flow", "Significant aortic regurgitation, showing systolic forward flow followed by diastolic reverse flow through the LVOT", "Mitral stenosis", "Pulmonic stenosis"], correctAnswer: 1, rationale: "The to-and-fro Doppler pattern in the LVOT shows systolic forward flow (normal ejection) immediately followed by holodiastolic reverse flow (AR jet entering the LV through the LVOT). This bidirectional pattern is characteristic and helps identify the level of regurgitation.", learningObjective: "Identify to-and-fro LVOT Doppler pattern", blueprintCategory: "Hemodynamic Measurements", subtopic: "Hemodynamic Calculations", difficulty: 2, cognitiveLevel: "recall", questionType: "multiple-choice", exam: "RDCS-AE", regionScope: "BOTH" },
    { stem: "In an echo lab quality improvement program, inter-observer variability for measurements should be:", options: ["Not monitored", "Regularly assessed and minimized through standardized measurement protocols, training, and periodic calibration exercises", "Only checked once at hire", "Expected to be very high"], correctAnswer: 1, rationale: "QI programs should include regular assessment of inter-observer variability for key measurements (EF, valve areas, gradients). Standardized protocols, periodic training, measurement audits, and correlation with reference standards help maintain measurement accuracy and consistency across sonographers.", learningObjective: "Describe QI for measurement variability", blueprintCategory: "Anatomy/Physiology", subtopic: "CSCT Exam Preparation", difficulty: 2, cognitiveLevel: "recall", questionType: "multiple-choice", exam: "CSCT-CARDIAC", regionScope: "CAN" },
    { stem: "A CSCT-style question: During a TTE, the sonographer notices a mobile echodensity on the aortic valve in a patient with fever. The immediate action should be:", options: ["Ignore it and continue", "Document the finding thoroughly with multiple views, measure the mass, assess for complications, and immediately notify the interpreting physician of the potential vegetation", "Wait until the study is complete before informing anyone", "Assume it is an artifact"], correctAnswer: 1, rationale: "A mobile valve mass in the setting of fever is a potential vegetation (infective endocarditis). The sonographer should: document thoroughly (multiple views, zoom, measure size), assess for valve destruction and regurgitation, look for perivalvular abscess, and immediately notify the physician for urgent clinical correlation.", learningObjective: "Describe sonographer response to potential vegetation", blueprintCategory: "Pathology Recognition", subtopic: "Valvular Disease Assessment", difficulty: 2, cognitiveLevel: "application", questionType: "clinical-case", exam: "CSCT-CARDIAC", regionScope: "CAN" },
  ];
}

export function getBatch47(): EQ[] {
  return [
    { stem: "The main pulmonary artery is normally:", options: ["Larger than the aorta", "Approximately equal to or slightly smaller than the ascending aorta (PA/Ao ratio ≤1.0); ratio >1.0 suggests PA dilation", "Always smaller than the aorta", "Not visible on echo"], correctAnswer: 1, rationale: "Normal MPA diameter: approximately equal to or slightly smaller than the ascending aorta. MPA/ascending aorta ratio >1.0 suggests PA dilation, often from pulmonary hypertension. Normal MPA diameter: ~21-29 mm. Values >29 mm or indexed >15 mm/m² suggest dilation.", learningObjective: "State normal PA/aorta relationship", blueprintCategory: "Anatomy/Physiology", subtopic: "Cardiac Anatomy", difficulty: 2, cognitiveLevel: "recall", questionType: "multiple-choice", exam: "RDCS-AE", regionScope: "BOTH" },
    { stem: "The Doppler beam should be aligned within how many degrees of blood flow for accurate velocity measurement?", options: ["Within 90 degrees", "Within 20 degrees (cos 20° = 0.94, <6% error)", "Within 60 degrees", "Angle does not matter"], correctAnswer: 1, rationale: "The Doppler equation includes cos θ. At angles ≤20°, the error is <6% (clinically acceptable). Beyond 20°, underestimation increases significantly. At 30°: 13% error. At 60°: 50% error. Parallel alignment (0°) gives the most accurate velocity measurement.", learningObjective: "State acceptable Doppler angle range", blueprintCategory: "Ultrasound Physics", subtopic: "Doppler Ultrasound", difficulty: 2, cognitiveLevel: "recall", questionType: "multiple-choice", exam: "RDCS-AE", regionScope: "BOTH" },
    { stem: "The Rastelli classification of AVSD types is based on:", options: ["ASD size", "The morphology and chordal attachment of the superior bridging leaflet of the common AV valve", "The presence of VSD only", "Patient age"], correctAnswer: 1, rationale: "Rastelli classification: Type A (most common): superior bridging leaflet attached to the crest of the ventricular septum with divided chordae. Type B: attached to an anomalous papillary muscle on the RV septum. Type C: free-floating superior bridging leaflet without septal attachments (most common in Down syndrome AVSD).", learningObjective: "Describe the Rastelli classification", blueprintCategory: "Pathology Recognition", subtopic: "Congenital Heart Defects", difficulty: 5, cognitiveLevel: "recall", questionType: "multiple-choice", exam: "RDCS-AE", regionScope: "BOTH" },
    { stem: "A partial AV canal defect (partial AVSD) includes:", options: ["Complete absence of the AV septum", "Ostium primum ASD with a cleft in the anterior mitral leaflet, but two separate AV valve orifices (no common valve)", "Only a VSD", "Only aortic anomaly"], correctAnswer: 1, rationale: "Partial AVSD: ostium primum ASD + cleft anterior mitral leaflet + two separate AV valve annuli (no common valve). The cleft causes variable MR. Complete AVSD has a common AV valve and both ASD and VSD components. Intermediate types have restricted VSD under the common valve.", learningObjective: "Describe partial AVSD components", blueprintCategory: "Pathology Recognition", subtopic: "Congenital Heart Defects", difficulty: 4, cognitiveLevel: "recall", questionType: "multiple-choice", exam: "RDCS-AE", regionScope: "BOTH" },
    { stem: "The normal mitral valve area by planimetry in a healthy adult is:", options: ["1.0-2.0 cm²", "2.0-3.0 cm²", "4.0-6.0 cm²", "8.0+ cm²"], correctAnswer: 2, rationale: "Normal MVA: 4.0-6.0 cm². Planimetry is performed in the PSAX at the leaflet tips level in early diastole. This is the reference standard for MVA measurement. The MV orifice is traced along the inner edge of the leaflets at maximum opening.", learningObjective: "State normal MVA by planimetry", blueprintCategory: "Hemodynamic Measurements", subtopic: "Hemodynamic Calculations", difficulty: 1, cognitiveLevel: "recall", questionType: "multiple-choice", exam: "RDCS-AE", regionScope: "BOTH" },
    { stem: "An Austin Flint murmur is associated with:", options: ["Mitral stenosis", "Severe aortic regurgitation, where the AR jet impinges on the anterior mitral leaflet, creating a functional mid-diastolic rumble that mimics MS", "Tricuspid stenosis", "Pulmonic stenosis"], correctAnswer: 1, rationale: "Austin Flint murmur: a low-pitched mid-to-late diastolic rumble at the apex caused by severe AR. The AR jet restricts anterior mitral leaflet opening and causes turbulence, creating a functional MS-like murmur. Echo differentiates this from true MS by showing a structurally normal MV.", learningObjective: "Identify the Austin Flint murmur", blueprintCategory: "Pathology Recognition", subtopic: "Valvular Disease Assessment", difficulty: 4, cognitiveLevel: "recall", questionType: "multiple-choice", exam: "RDCS-AE", regionScope: "BOTH" },
    { stem: "The normal LV internal dimension in systole (LVIDs) for adult males is:", options: ["15-25 mm", "25-40 mm", "45-55 mm", "55-65 mm"], correctAnswer: 1, rationale: "Normal LVIDs for males: approximately 25-40 mm. It is measured in the PLAX using M-mode at peak systole. LVIDs >40 mm in chronic MR is a Class I indication for surgical intervention, as it indicates LV systolic dysfunction.", learningObjective: "State normal LVIDs", blueprintCategory: "Hemodynamic Measurements", subtopic: "Chamber Quantification", difficulty: 2, cognitiveLevel: "recall", questionType: "multiple-choice", exam: "RDCS-AE", regionScope: "BOTH" },
    { stem: "In HCM, mid-cavitary obstruction occurs when:", options: ["SAM is present", "Hypertrophied papillary muscles or mid-ventricular segments create obstruction at the mid-cavity level rather than the LVOT", "Only in apical HCM", "Only with fixed subaortic membrane"], correctAnswer: 1, rationale: "Mid-cavitary obstruction in HCM: hypertrophied papillary muscles and mid-ventricular walls narrow the mid-cavity, creating a pressure gradient. This is different from LVOT obstruction and may coexist with it. Mid-cavity obstruction can cause apical aneurysm formation from high distal pressures.", learningObjective: "Describe mid-cavitary obstruction in HCM", blueprintCategory: "Pathology Recognition", subtopic: "Cardiomyopathies", difficulty: 4, cognitiveLevel: "comprehension", questionType: "multiple-choice", exam: "RDCS-AE", regionScope: "BOTH" },
    { stem: "The Brockenbrough-Braunwald-Morrow sign in HCM is demonstrated when:", options: ["Gradient decreases post-PVC", "The LVOT gradient increases and pulse pressure decreases in the beat following a premature ventricular contraction", "No change occurs post-PVC", "Gradient normalizes after PVC"], correctAnswer: 1, rationale: "Post-PVC potentiation: the post-PVC beat has increased contractility (Frank-Starling) and reduced loading, which in HCM causes increased LVOT obstruction. The aortic pulse pressure paradoxically decreases despite the increased contractility (unlike fixed AS where pulse pressure increases post-PVC).", learningObjective: "Describe the Brockenbrough sign", blueprintCategory: "Pathology Recognition", subtopic: "Cardiomyopathies", difficulty: 5, cognitiveLevel: "analysis", questionType: "multiple-choice", exam: "RDCS-AE", regionScope: "BOTH" },
    { stem: "Echo evaluation of a patient with radiation heart disease may show:", options: ["Only normal findings", "Pericardial thickening/constriction, valve fibrosis/calcification (especially aortic and mitral), CAD, and restrictive cardiomyopathy", "Only valve disease", "Only pericardial disease"], correctAnswer: 1, rationale: "Radiation heart disease affects all cardiac structures: pericardium (thickening, constriction), valves (fibrosis, calcification, regurgitation or stenosis), myocardium (restrictive cardiomyopathy, diastolic dysfunction), coronary arteries (accelerated CAD), and conduction system. Effects may appear years after radiation.", learningObjective: "Describe radiation heart disease echo findings", blueprintCategory: "Pathology Recognition", subtopic: "Cardiomyopathies", difficulty: 3, cognitiveLevel: "recall", questionType: "multiple-choice", exam: "RDCS-AE", regionScope: "BOTH" },
    { stem: "A CSCT exam question: the ultrasound bioeffects ALARA principle applies to:", options: ["Only MRI", "All diagnostic ultrasound including echocardiography, with particular attention to output power, examination duration, and appropriate use of Doppler modes", "Only obstetric ultrasound", "Only therapeutic ultrasound"], correctAnswer: 1, rationale: "ALARA applies to all ultrasound examinations including echocardiography. Sonographers should use the minimum output power necessary, minimize total scan time, and be aware that CW and color Doppler have higher intensities than B-mode imaging. The MI and TI should be monitored.", learningObjective: "Apply ALARA to echocardiography", blueprintCategory: "Ultrasound Physics", subtopic: "Echo Imaging Physics", difficulty: 1, cognitiveLevel: "recall", questionType: "multiple-choice", exam: "CSCT-CARDIAC", regionScope: "CAN" },
    { stem: "Coronary artery anomalies that may be detected on echo include:", options: ["All anomalies", "Anomalous origin from the wrong sinus, ALCAPA, coronary AV fistula, and aneurysmal dilation (Kawasaki disease)", "Only fistulas", "Coronary anomalies cannot be seen on echo"], correctAnswer: 1, rationale: "Echo can detect: anomalous coronary origin from the wrong sinus (PSAX at AV level), ALCAPA (dilated RCA, abnormal flow in PA), coronary AV fistula (dilated coronary with flow into a cardiac chamber), and coronary aneurysms in Kawasaki disease. CT/MRI are more definitive for complex anomalies.", learningObjective: "List detectable coronary anomalies on echo", blueprintCategory: "Pathology Recognition", subtopic: "Congenital Heart Defects", difficulty: 3, cognitiveLevel: "recall", questionType: "multiple-choice", exam: "RDCS-AE", regionScope: "BOTH" },
    { stem: "Kawasaki disease can cause coronary artery aneurysms. Echo follow-up should assess:", options: ["Only LV function", "Coronary artery dimensions (Z-scores), aneurysm morphology, thrombus within aneurysms, LV function, and valve regurgitation", "Only pericardial effusion", "Only MR"], correctAnswer: 1, rationale: "Kawasaki echo follow-up: coronary artery dimensions using Z-scores (BSA-adjusted), aneurysm morphology (fusiform vs. saccular), intraluminal thrombus (especially in giant aneurysms >8 mm), LV function, MR (from papillary ischemia), and pericardial effusion. Serial echo is essential for long-term surveillance.", learningObjective: "Describe Kawasaki echo follow-up assessment", blueprintCategory: "Pathology Recognition", subtopic: "Congenital Heart Defects", difficulty: 3, cognitiveLevel: "recall", questionType: "multiple-choice", exam: "RDCS-AE", regionScope: "BOTH" },
    { stem: "In Canadian practice, continuing professional development (CPD) for CSCT-certified sonographers:", options: ["Is not required", "Is mandatory and requires documented continuing education hours in cardiac sonography to maintain certification", "Is optional", "Only applies to physicians"], correctAnswer: 1, rationale: "CSCT-certified sonographers must complete mandatory CPD to maintain their certification. This includes documented continuing education hours in cardiac sonography, attendance at conferences/workshops, and demonstration of ongoing competency. CPD ensures sonographers stay current with evolving standards.", learningObjective: "Describe CSCT CPD requirements", blueprintCategory: "Anatomy/Physiology", subtopic: "CSCT Exam Preparation", difficulty: 1, cognitiveLevel: "recall", questionType: "multiple-choice", exam: "CSCT-CARDIAC", regionScope: "CAN" },
  ];
}

export function getBatch48(): EQ[] {
  return [
    { stem: "The subclavian steal phenomenon can be assessed by:", options: ["Only angiography", "PW Doppler of the vertebral arteries showing retrograde flow on the affected side, and reduced arm blood pressure on the ipsilateral side", "M-mode only", "Only MRI"], correctAnswer: 1, rationale: "Subclavian steal: proximal subclavian artery stenosis causes retrograde flow in the ipsilateral vertebral artery to supply the arm. Echo/vascular ultrasound shows reversed vertebral artery flow. Associated with left subclavian stenosis (more common) and can cause vertebrobasilar insufficiency symptoms.", learningObjective: "Describe subclavian steal assessment", blueprintCategory: "Hemodynamic Measurements", subtopic: "Hemodynamics", difficulty: 4, cognitiveLevel: "recall", questionType: "multiple-choice", exam: "RDCS-AE", regionScope: "BOTH" },
    { stem: "In the assessment of aortic regurgitation, the jet width/LVOT ratio on color Doppler in the PLAX view for severe AR is:", options: ["<25%", "25-45%", "≥65%", "Not measurable"], correctAnswer: 2, rationale: "AR jet width/LVOT diameter ratio: <25% = mild, 25-64% = moderate, ≥65% = severe. Measured in the PLAX view at the level of the aortic valve. This is a semi-quantitative method that complements vena contracta, EROA, and PHT assessments.", learningObjective: "State AR jet width/LVOT ratio for severity", blueprintCategory: "Hemodynamic Measurements", subtopic: "Hemodynamic Calculations", difficulty: 2, cognitiveLevel: "recall", questionType: "multiple-choice", exam: "RDCS-AE", regionScope: "BOTH" },
    { stem: "The Doppler half-time for severe mitral stenosis is:", options: ["<100 ms", "100-150 ms", ">220 ms (MVA = 220/PHT)", "<50 ms"], correctAnswer: 2, rationale: "Severe MS: PHT >220 ms (MVA = 220/PHT <1.0 cm²). Moderate: PHT 150-220 ms (MVA 1.0-1.5). Mild: PHT <150 ms (MVA >1.5). The PHT method may be inaccurate after valvuloplasty, with significant AR, or with markedly elevated LA pressure.", learningObjective: "State PHT for severe MS", blueprintCategory: "Hemodynamic Measurements", subtopic: "Hemodynamic Calculations", difficulty: 2, cognitiveLevel: "recall", questionType: "multiple-choice", exam: "RDCS-AE", regionScope: "BOTH" },
    { stem: "An echo shows a vegetation on the atrial side of the mitral valve. The vegetation is:", options: ["On the high-pressure side", "On the low-pressure side (atrial side during systole when MR creates low pressure), which is the typical location for mitral valve vegetations", "Randomly located", "Always on the ventricular side"], correctAnswer: 1, rationale: "Vegetations typically attach to the low-pressure side of valves: atrial side of AV valves (mitral, tricuspid) and ventricular side of semilunar valves (aortic, pulmonic). This is because the turbulent regurgitant jet creates endothelial damage on the downstream (low-pressure) surface.", learningObjective: "Explain vegetation location based on hemodynamics", blueprintCategory: "Pathology Recognition", subtopic: "Valvular Disease Assessment", difficulty: 3, cognitiveLevel: "comprehension", questionType: "multiple-choice", exam: "RDCS-AE", regionScope: "BOTH" },
    { stem: "In CSCT practice, the sonographer encountering a technically difficult study should:", options: ["Abbreviate the study", "Use all available techniques to optimize images: alternative windows, patient repositioning, harmonic imaging, contrast if indicated, and document any limitations", "Cancel the study", "Skip difficult views"], correctAnswer: 1, rationale: "For technically difficult studies: try alternative windows, reposition the patient, use harmonic imaging, adjust gain/depth/focus, consider IV contrast for LV opacification (if ≥2 contiguous segments are poorly visualized), and document limitations in the study. A suboptimal study should still attempt all standard views.", learningObjective: "Describe approach to technically difficult studies", blueprintCategory: "Anatomy/Physiology", subtopic: "CSCT Exam Preparation", difficulty: 2, cognitiveLevel: "recall", questionType: "multiple-choice", exam: "CSCT-CARDIAC", regionScope: "CAN" },
    { stem: "A normal tricuspid annular diameter in the A4C view at end-diastole is:", options: ["<20 mm", "<28 mm", "<40 mm", "≥50 mm indicates dilation"], correctAnswer: 2, rationale: "Normal tricuspid annular diameter: <40 mm (or <21 mm/m²) at end-diastole in the A4C view. Annular dilation >40 mm is associated with functional TR. Annuloplasty is considered for annular dilation ≥40 mm even in the absence of significant TR at the time of left-sided valve surgery.", learningObjective: "State normal tricuspid annular diameter", blueprintCategory: "Hemodynamic Measurements", subtopic: "Chamber Quantification", difficulty: 2, cognitiveLevel: "recall", questionType: "multiple-choice", exam: "RDCS-AE", regionScope: "BOTH" },
    { stem: "Color M-mode propagation velocity (Vp) is used in diastolic function assessment. A Vp <45 cm/s suggests:", options: ["Normal relaxation", "Impaired LV relaxation (delayed filling propagation from base to apex)", "Constrictive pericarditis", "Pericardial effusion"], correctAnswer: 1, rationale: "Color M-mode Vp: measures the slope of the early diastolic filling wavefront from the mitral annulus to the apex. Normal Vp ≥45 cm/s. Vp <45 cm/s indicates impaired relaxation. E/Vp >2.5 suggests elevated filling pressures. Vp is less preload-dependent than E velocity.", learningObjective: "Interpret color M-mode Vp", blueprintCategory: "Hemodynamic Measurements", subtopic: "Diastolic Function Assessment", difficulty: 4, cognitiveLevel: "comprehension", questionType: "multiple-choice", exam: "RDCS-AE", regionScope: "BOTH" },
    { stem: "The standard electrocardiographic leads monitored during an echo exam typically include:", options: ["No ECG monitoring", "At least a 3-lead ECG for timing measurements and gating of the cardiac cycle", "12-lead ECG always", "Only pulse oximetry"], correctAnswer: 1, rationale: "ECG monitoring during echo: at least 3 leads for: timing measurements (end-diastole at QRS onset), gating digital clips, identifying arrhythmias, and ensuring measurements are taken at appropriate points in the cardiac cycle. Some systems use 1-lead but 3-lead is standard.", learningObjective: "State ECG monitoring requirements during echo", blueprintCategory: "Anatomy/Physiology", subtopic: "Echo Imaging Views", difficulty: 1, cognitiveLevel: "recall", questionType: "multiple-choice", exam: "RDCS-AE", regionScope: "BOTH" },
    { stem: "In the evaluation of pulmonic stenosis severity, severe PS is defined by:", options: ["Peak velocity <2 m/s", "Peak velocity >4 m/s or peak gradient >64 mmHg with RV hypertrophy", "Peak velocity 2-3 m/s", "Only valve morphology"], correctAnswer: 1, rationale: "PS severity: mild (peak velocity <3 m/s, gradient <36 mmHg), moderate (3-4 m/s, gradient 36-64 mmHg), severe (>4 m/s, gradient >64 mmHg). Severe PS is associated with RV hypertrophy, RV dilation, TR, and may require balloon valvuloplasty or surgery.", learningObjective: "State criteria for severe pulmonic stenosis", blueprintCategory: "Hemodynamic Measurements", subtopic: "Hemodynamic Calculations", difficulty: 2, cognitiveLevel: "recall", questionType: "multiple-choice", exam: "RDCS-AE", regionScope: "BOTH" },
    { stem: "The echo finding of a dilated main pulmonary artery (>29 mm) with RV dilation and elevated TR velocity suggests:", options: ["Normal variant", "Pulmonary hypertension until proven otherwise", "Only left heart disease", "Only COPD"], correctAnswer: 1, rationale: "MPA dilation >29 mm combined with RV dilation and elevated TR velocity strongly suggests pulmonary hypertension. Additional supportive findings: RVOT acceleration time <105 ms, RV hypertrophy, IVC dilation, RA enlargement, and D-shaped LV. Right heart catheterization confirms the diagnosis.", learningObjective: "Recognize echo constellation suggesting PH", blueprintCategory: "Pathology Recognition", subtopic: "Hemodynamics", difficulty: 2, cognitiveLevel: "analysis", questionType: "multiple-choice", exam: "RDCS-AE", regionScope: "BOTH" },
    { stem: "An echo shows a thrombus in transit through the right heart. This finding:", options: ["Is benign", "Is a medical emergency as it indicates active venous thromboembolism with high risk of massive PE and requires immediate anticoagulation and possibly intervention", "Requires no intervention", "Is always an artifact"], correctAnswer: 1, rationale: "Right heart thrombus in transit: a mobile thrombus seen in the RA, RV, or straddling the PFO, originating from deep venous thrombosis. It carries high mortality risk (>40% without treatment) from massive PE. Emergency management includes anticoagulation, thrombolysis, surgical embolectomy, or catheter-based intervention.", learningObjective: "Identify right heart thrombus in transit urgency", blueprintCategory: "Pathology Recognition", subtopic: "Cardiac Masses", difficulty: 4, cognitiveLevel: "analysis", questionType: "clinical-case", exam: "RDCS-AE", regionScope: "BOTH" },
    { stem: "CSCT candidates should know that the transducer frequency for adult transthoracic echocardiography is typically:", options: ["1 MHz", "2-4 MHz (phased array)", "7-12 MHz", "15-20 MHz"], correctAnswer: 1, rationale: "Adult TTE: 2-4 MHz phased array transducer. Lower frequency (2-2.5 MHz) for larger patients or deeper structures; higher frequency (3-4 MHz) for thinner patients or better near-field resolution. Pediatric TTE may use 5-8 MHz. TEE probes use 3-7 MHz multiplane phased array.", learningObjective: "State standard TTE transducer frequency", blueprintCategory: "Ultrasound Physics", subtopic: "Echo Imaging Physics", difficulty: 1, cognitiveLevel: "recall", questionType: "multiple-choice", exam: "CSCT-CARDIAC", regionScope: "CAN" },
    { stem: "The LV internal dimension should be measured at the onset of the QRS complex because this represents:", options: ["Peak systole", "End-diastole, when the ventricle is at its maximum volume before contraction begins", "Mid-diastole", "Atrial systole"], correctAnswer: 1, rationale: "End-diastole is defined as the onset of the QRS complex (beginning of ventricular depolarization). At this point, the LV is at maximum volume (after atrial filling). End-systole is at the smallest LV dimension or at aortic valve closure. These timing landmarks ensure reproducible measurements.", learningObjective: "Explain timing of end-diastolic measurement", blueprintCategory: "Hemodynamic Measurements", subtopic: "Chamber Quantification", difficulty: 1, cognitiveLevel: "recall", questionType: "multiple-choice", exam: "RDCS-AE", regionScope: "BOTH" },
    { stem: "In the echo assessment of a patient with suspected cardiac contusion (blunt chest trauma), findings may include:", options: ["Only pericardial effusion", "RV wall motion abnormality (RV is most vulnerable), pericardial effusion, valve damage, and potentially cardiac rupture", "Only LV dysfunction", "Normal echo always"], correctAnswer: 1, rationale: "Cardiac contusion: RV is the most anterior chamber and most susceptible to blunt trauma. Echo findings: RV wall motion abnormalities, pericardial effusion (hemopericardium), valve rupture (especially tricuspid), and rarely free wall rupture or septal defect. Serial echo may be needed as findings can evolve.", learningObjective: "Describe echo findings in cardiac contusion", blueprintCategory: "Pathology Recognition", subtopic: "Cardiac Masses", difficulty: 3, cognitiveLevel: "recall", questionType: "multiple-choice", exam: "RDCS-AE", regionScope: "BOTH" },
  ];
}

export function getBatch49(): EQ[] {
  return [
    { stem: "The normal pulmonic valve is:", options: ["Trileaflet like the aortic valve", "Trileaflet (anterior, right, and left cusps) and thinner than the aortic valve; the thinnest of all cardiac valves", "Bicuspid normally", "Quadricuspid normally"], correctAnswer: 1, rationale: "The pulmonic valve has three thin semilunar cusps: anterior, right, and left. It is the thinnest and most anterior of the cardiac valves. It is best visualized in the PSAX at the AV level (showing RVOT and PV) and the RV inflow-outflow view.", learningObjective: "Describe normal pulmonic valve anatomy", blueprintCategory: "Anatomy/Physiology", subtopic: "Cardiac Anatomy", difficulty: 1, cognitiveLevel: "recall", questionType: "multiple-choice", exam: "RDCS-AE", regionScope: "BOTH" },
    { stem: "A unicuspid aortic valve is:", options: ["The most common valve variant", "A rare congenital anomaly that may present with severe AS in childhood or young adulthood, with a single commissure", "Always discovered incidentally in elderly", "A normal variant"], correctAnswer: 1, rationale: "Unicuspid aortic valve: rare congenital anomaly with a single commissure and eccentric orifice. Two types: unicommissural (more common) and acommissural. Presents with severe AS early in life (childhood to young adulthood) because the single orifice is inherently stenotic. Requires early intervention.", learningObjective: "Describe unicuspid aortic valve", blueprintCategory: "Pathology Recognition", subtopic: "Congenital Heart Defects", difficulty: 4, cognitiveLevel: "recall", questionType: "multiple-choice", exam: "RDCS-AE", regionScope: "BOTH" },
    { stem: "The echo finding of a double-orifice mitral valve shows:", options: ["A single normal orifice", "Two distinct orifices in the PSAX view at the MV level, which may be congenital or iatrogenic (post-MitraClip)", "Three orifices", "No visible orifice"], correctAnswer: 1, rationale: "Double-orifice mitral valve: two distinct mitral openings seen in PSAX at the MV tips level. Congenital double-orifice MV is associated with AVSD and may cause MR or MS. Iatrogenic double-orifice is the expected result after MitraClip (edge-to-edge repair), creating two symmetric orifices.", learningObjective: "Identify double-orifice mitral valve", blueprintCategory: "Pathology Recognition", subtopic: "Congenital Heart Defects", difficulty: 3, cognitiveLevel: "recall", questionType: "multiple-choice", exam: "RDCS-AE", regionScope: "BOTH" },
    { stem: "When measuring the aortic root, the standard levels of measurement include:", options: ["Only one level", "Annulus, sinuses of Valsalva, sinotubular junction, and tubular ascending aorta", "Only the arch", "Descending aorta only"], correctAnswer: 1, rationale: "Aortic root measurement levels (PLAX, leading-edge-to-leading-edge in diastole per ASE): 1) annulus (for LVOT area), 2) sinuses of Valsalva (widest portion, most relevant for aneurysm screening), 3) sinotubular junction, and 4) proximal tubular ascending aorta.", learningObjective: "List aortic root measurement levels", blueprintCategory: "Hemodynamic Measurements", subtopic: "Chamber Quantification", difficulty: 2, cognitiveLevel: "recall", questionType: "multiple-choice", exam: "RDCS-AE", regionScope: "BOTH" },
    { stem: "In the CSCT exam, knowledge of the ASE chamber quantification guidelines includes:", options: ["Only EF measurement", "Standardized methods for measuring all cardiac chambers, wall thickness, LV mass, and aortic dimensions with gender-specific normal reference ranges", "Only qualitative assessment", "No standardized guidelines exist"], correctAnswer: 1, rationale: "ASE chamber quantification guidelines provide standardized measurement methods, imaging planes, and gender-specific normal reference ranges for: LV dimensions and volumes, LV mass, LA volume, RV dimensions and function, RA area, aortic dimensions, and wall thickness. These are the foundation of quantitative echo.", learningObjective: "Describe ASE chamber quantification scope", blueprintCategory: "Hemodynamic Measurements", subtopic: "Chamber Quantification", difficulty: 2, cognitiveLevel: "recall", questionType: "multiple-choice", exam: "CSCT-CARDIAC", regionScope: "CAN" },
    { stem: "The finding of diastolic septal flattening in combination with systolic septal flattening suggests:", options: ["Only volume overload", "Combined RV volume AND pressure overload, often seen in severe PH with significant TR", "Only pressure overload", "Normal finding"], correctAnswer: 1, rationale: "Combined systolic and diastolic septal flattening indicates both RV pressure (systolic) and volume (diastolic) overload. This is commonly seen in severe pulmonary hypertension with significant TR (pressure + regurgitant volume overload). The LV appears D-shaped throughout the cardiac cycle.", learningObjective: "Interpret combined septal flattening", blueprintCategory: "Pathology Recognition", subtopic: "Hemodynamics", difficulty: 3, cognitiveLevel: "analysis", questionType: "multiple-choice", exam: "RDCS-AE", regionScope: "BOTH" },
    { stem: "The normal mitral inflow deceleration time (DT) is:", options: ["<100 ms", "160-220 ms", "300-400 ms", ">500 ms"], correctAnswer: 1, rationale: "Normal mitral DT: 160-220 ms (may extend to 240 ms in older adults). Prolonged DT (>220 ms): impaired relaxation (Grade I diastolic dysfunction). Shortened DT (<160 ms): restrictive filling with elevated LA pressure (Grade III). DT is measured from the E peak to baseline.", learningObjective: "State normal mitral DT", blueprintCategory: "Hemodynamic Measurements", subtopic: "Diastolic Function Assessment", difficulty: 2, cognitiveLevel: "recall", questionType: "multiple-choice", exam: "RDCS-AE", regionScope: "BOTH" },
    { stem: "A patient with peripartum cardiomyopathy typically presents with:", options: ["LV hypertrophy", "New-onset heart failure with LV dilation and reduced EF in the last month of pregnancy or the first 5 months postpartum", "Only right heart failure", "Normal echo"], correctAnswer: 1, rationale: "Peripartum cardiomyopathy: new-onset heart failure with reduced EF (<45%) in the last month of pregnancy to 5 months postpartum, without other identifiable cause. Echo shows DCM pattern: LV dilation, reduced EF, functional MR, possible LV thrombus. EF recovery occurs in ~50% of cases.", learningObjective: "Describe peripartum cardiomyopathy echo findings", blueprintCategory: "Pathology Recognition", subtopic: "Cardiomyopathies", difficulty: 3, cognitiveLevel: "recall", questionType: "multiple-choice", exam: "RDCS-AE", regionScope: "BOTH" },
    { stem: "The echo sign of 'early systolic closure' of the aortic valve on M-mode suggests:", options: ["Normal valve function", "Dynamic LVOT obstruction (as in HCM) or discrete subaortic stenosis, where the valve initially opens normally then partially closes as obstruction develops", "Fixed aortic stenosis", "Aortic regurgitation"], correctAnswer: 1, rationale: "Early systolic closure (or mid-systolic closure/notching) of the aortic valve on M-mode is characteristic of dynamic LVOT obstruction (HCM with SAM). The valve opens normally but then partially closes as the LVOT gradient increases during mid-to-late systole. In fixed AS, the valve opening is consistently reduced.", learningObjective: "Identify AV early systolic closure on M-mode", blueprintCategory: "Pathology Recognition", subtopic: "Cardiomyopathies", difficulty: 4, cognitiveLevel: "recall", questionType: "multiple-choice", exam: "RDCS-AE", regionScope: "BOTH" },
    { stem: "An echo calculation: heart rate 80 bpm, LVOT diameter 2.0 cm, LVOT VTI 20 cm. What is the cardiac output?", options: ["2.5 L/min", "4.0 L/min", "5.0 L/min", "6.5 L/min"], correctAnswer: 2, rationale: "LVOT area = π(1.0)² = 3.14 cm². SV = 3.14 × 20 = 62.8 mL. CO = SV × HR = 62.8 × 80 / 1000 = 5.02 L/min ≈ 5.0 L/min. This is within the normal range of 4-8 L/min.", learningObjective: "Calculate cardiac output from echo data", blueprintCategory: "Hemodynamic Measurements", subtopic: "Hemodynamic Calculations", difficulty: 3, cognitiveLevel: "application", questionType: "calculation", exam: "RDCS-AE", regionScope: "BOTH" },
    { stem: "In CSCT practice, the sonographer should document the following minimum views for a complete TTE report:", options: ["Only 3 views", "All standard parasternal, apical, subcostal, and suprasternal views with appropriate 2D, M-mode, color Doppler, and spectral Doppler documentation", "Only Doppler tracings", "Only apical views"], correctAnswer: 1, rationale: "Complete TTE documentation: all standard 2D views, M-mode measurements (LV, aortic root, LA), color Doppler of all four valves, PW Doppler (LVOT, mitral inflow, PV, hepatic vein, TDI), CW Doppler (all regurgitant and stenotic jets), and subcostal IVC assessment. All clips and images should be properly labeled.", learningObjective: "List minimum documentation for complete TTE", blueprintCategory: "Anatomy/Physiology", subtopic: "CSCT Exam Preparation", difficulty: 2, cognitiveLevel: "recall", questionType: "multiple-choice", exam: "CSCT-CARDIAC", regionScope: "CAN" },
    { stem: "The Hagen-Poiseuille equation relates flow through a tube to:", options: ["Only pressure", "The pressure gradient, tube radius (4th power), tube length, and fluid viscosity", "Only tube diameter", "Only velocity"], correctAnswer: 1, rationale: "Hagen-Poiseuille: Q = (ΔP × π × r⁴) / (8 × η × L), where Q = flow, ΔP = pressure gradient, r = radius, η = viscosity, L = length. Flow is proportional to r⁴ — halving the radius reduces flow 16-fold. This explains why small changes in vessel/valve radius dramatically affect flow.", learningObjective: "Describe the Hagen-Poiseuille equation relevance", blueprintCategory: "Anatomy/Physiology", subtopic: "Cardiac Physiology", difficulty: 4, cognitiveLevel: "comprehension", questionType: "multiple-choice", exam: "RDCS-AE", regionScope: "BOTH" },
    { stem: "The normal RV basal diameter in the A4C view is:", options: ["<20 mm", "<25 mm", "25-41 mm", ">50 mm"], correctAnswer: 2, rationale: "Normal RV basal diameter: 25-41 mm in the A4C view at end-diastole. Mid-RV diameter: 19-35 mm. RV length: 59-83 mm. Basal RV diameter >41 mm indicates RV dilation. RV dimensions are measured at end-diastole in the RV-focused A4C view.", learningObjective: "State normal RV basal diameter", blueprintCategory: "Hemodynamic Measurements", subtopic: "Chamber Quantification", difficulty: 2, cognitiveLevel: "recall", questionType: "multiple-choice", exam: "RDCS-AE", regionScope: "BOTH" },
  ];
}

export function getBatch50(): EQ[] {
  return [
    { stem: "An echo shows a patient with Williams syndrome. The expected cardiac finding is:", options: ["Mitral prolapse", "Supravalvular aortic stenosis and peripheral pulmonary stenosis", "Ebstein anomaly", "Tetralogy of Fallot"], correctAnswer: 1, rationale: "Williams syndrome (7q11.23 deletion, elastin gene): supravalvular aortic stenosis (hourglass narrowing above the STJ), peripheral pulmonary artery stenosis, and elastin arteriopathy. Echo shows narrowing above the AV, elevated velocities, and possible coronary ostial involvement.", learningObjective: "Identify Williams syndrome cardiac findings", blueprintCategory: "Pathology Recognition", subtopic: "Congenital Heart Defects", difficulty: 3, cognitiveLevel: "recall", questionType: "multiple-choice", exam: "RDCS-AE", regionScope: "BOTH" },
    { stem: "The echo measurement of MAPSE (mitral annular plane systolic excursion) provides:", options: ["Diastolic function assessment", "A rapid measure of LV longitudinal systolic function; MAPSE <10 mm suggests reduced LV systolic function", "Valve area calculation", "Pressure gradient estimation"], correctAnswer: 1, rationale: "MAPSE: M-mode cursor at the lateral or septal mitral annulus in A4C, measuring longitudinal excursion during systole. Normal: ≥10-12 mm (lateral), ≥8-10 mm (septal). MAPSE <10 mm correlates with reduced EF. It is the LV equivalent of TAPSE for the RV.", learningObjective: "Describe MAPSE measurement and interpretation", blueprintCategory: "Hemodynamic Measurements", subtopic: "Chamber Quantification", difficulty: 2, cognitiveLevel: "recall", questionType: "multiple-choice", exam: "RDCS-AE", regionScope: "BOTH" },
    { stem: "The echo finding of a 'coaptation depth' >10 mm in functional MR predicts:", options: ["Good surgical outcome", "Poor outcome with annuloplasty alone, as it indicates significant leaflet tethering from ventricular remodeling", "Normal anatomy", "Rheumatic disease"], correctAnswer: 1, rationale: "Coaptation depth (tenting height): distance from the mitral annular plane to the coaptation point. Values >10 mm in functional MR predict persistent MR after isolated annuloplasty ring repair, suggesting need for additional subvalvular intervention or consideration of MitraClip/replacement.", learningObjective: "Interpret coaptation depth in functional MR", blueprintCategory: "Pathology Recognition", subtopic: "Valvular Disease Assessment", difficulty: 4, cognitiveLevel: "application", questionType: "multiple-choice", exam: "RDCS-AE", regionScope: "BOTH" },
    { stem: "An echo shows elevated pulmonary artery systolic pressure. The differential diagnosis includes:", options: ["Only primary pulmonary hypertension", "Left heart disease (most common), pulmonary disease (COPD, ILD), chronic thromboembolic PH, and primary pulmonary arterial hypertension", "Only lung disease", "Only congenital heart disease"], correctAnswer: 1, rationale: "Elevated PASP differential: Group 1 (PAH — primary/idiopathic), Group 2 (left heart disease — most common overall), Group 3 (lung disease/hypoxia), Group 4 (CTEPH), Group 5 (miscellaneous). Echo can help differentiate by assessing LV diastolic function, valve disease, and shunt lesions.", learningObjective: "List differential diagnosis for elevated PASP", blueprintCategory: "Pathology Recognition", subtopic: "Hemodynamics", difficulty: 2, cognitiveLevel: "recall", questionType: "multiple-choice", exam: "RDCS-AE", regionScope: "BOTH" },
    { stem: "The spectral Doppler envelope density correlates with:", options: ["Image quality only", "The number of red blood cells moving at that velocity; dense envelopes indicate more blood at that velocity and can grade regurgitation severity", "Transducer frequency", "Patient size"], correctAnswer: 1, rationale: "CW Doppler signal density reflects the number of RBCs contributing to the signal. Dense, complete envelopes (especially for regurgitant jets) suggest large regurgitant volume (severe). Faint, incomplete envelopes suggest small regurgitant volume (mild). This is a qualitative severity assessment tool.", learningObjective: "Interpret Doppler signal density for severity", blueprintCategory: "Hemodynamic Measurements", subtopic: "Hemodynamic Calculations", difficulty: 3, cognitiveLevel: "comprehension", questionType: "multiple-choice", exam: "RDCS-AE", regionScope: "BOTH" },
    { stem: "An echo in a patient with end-stage renal disease commonly shows:", options: ["Normal echo", "LV hypertrophy (pressure + volume overload), diastolic dysfunction, calcific valve disease, pericardial effusion, and elevated filling pressures", "Only pericardial effusion", "Only dilated cardiomyopathy"], correctAnswer: 1, rationale: "ESRD cardiac findings: LVH (from hypertension and volume overload), diastolic dysfunction, accelerated valve calcification (especially aortic and mitral annular calcification from calcium-phosphate metabolism abnormalities), uremic pericardial effusion, and elevated filling pressures from fluid overload.", learningObjective: "Describe echo findings in ESRD", blueprintCategory: "Pathology Recognition", subtopic: "Cardiomyopathies", difficulty: 2, cognitiveLevel: "recall", questionType: "multiple-choice", exam: "RDCS-AE", regionScope: "BOTH" },
    { stem: "The CSCT exam requires knowledge of normal variants that may be confused with pathology. The crista terminalis is:", options: ["Always pathologic", "A normal muscular ridge in the posterolateral RA that can be mistaken for a mass or thrombus", "A congenital defect", "Found in the LV"], correctAnswer: 1, rationale: "Crista terminalis: a normal muscular ridge on the posterolateral RA wall (junction of the smooth-walled sinus venarum and the trabeculated appendage). It can be prominent and mimic an RA mass on echo. It is fixed, does not prolapse through the TV, and does not change with different views.", learningObjective: "Identify the crista terminalis as a normal variant", blueprintCategory: "Anatomy/Physiology", subtopic: "Cardiac Anatomy", difficulty: 2, cognitiveLevel: "recall", questionType: "multiple-choice", exam: "CSCT-CARDIAC", regionScope: "CAN" },
    { stem: "The echo assessment of a patient with suspected pulmonary embolism should evaluate:", options: ["Only LV function", "RV size and function (dilation, hypokinesis), McConnell sign, TR and RVSP, IVC, septal position, and possible visualization of thrombus in RA/RV or PA", "Only pericardial effusion", "Only aortic valve"], correctAnswer: 1, rationale: "PE echo assessment: RV dilation and dysfunction (most important), McConnell sign, elevated RVSP (but may be only mildly elevated in acute PE), IVC dilation, D-shaped LV, possible direct visualization of thrombus, and the 60/60 sign. Normal echo does not exclude PE.", learningObjective: "Describe echo assessment for PE", blueprintCategory: "Pathology Recognition", subtopic: "Hemodynamics", difficulty: 3, cognitiveLevel: "recall", questionType: "multiple-choice", exam: "RDCS-AE", regionScope: "BOTH" },
    { stem: "The Lutembacher syndrome is a combination of:", options: ["VSD and PS", "ASD (usually secundum) and mitral stenosis (usually rheumatic)", "PDA and coarctation", "Ebstein anomaly and WPW"], correctAnswer: 1, rationale: "Lutembacher syndrome: ASD (typically secundum, may be congenital) combined with MS (typically rheumatic). The ASD provides a decompression pathway for elevated LA pressure in MS, resulting in large left-to-right shunting and right heart volume overload. Treatment addresses both lesions.", learningObjective: "Define Lutembacher syndrome", blueprintCategory: "Pathology Recognition", subtopic: "Congenital Heart Defects", difficulty: 4, cognitiveLevel: "recall", questionType: "multiple-choice", exam: "RDCS-AE", regionScope: "BOTH" },
    { stem: "In the CSCT exam, the difference between a preliminary report and a final echo report is:", options: ["They are the same", "The preliminary report/worksheet is completed by the sonographer during or immediately after the study; the final report is issued and signed by the interpreting physician", "Only the physician writes reports", "Only the sonographer writes reports"], correctAnswer: 1, rationale: "Preliminary report (worksheet): completed by the sonographer, includes measurements, findings, and preliminary impressions. It guides the physician's review. Final report: issued by the interpreting physician (cardiologist) after reviewing images, measurements, and clinical context. The sonographer's role is acquisition and preliminary analysis.", learningObjective: "Differentiate preliminary from final echo report", blueprintCategory: "Anatomy/Physiology", subtopic: "CSCT Exam Preparation", difficulty: 1, cognitiveLevel: "recall", questionType: "multiple-choice", exam: "CSCT-CARDIAC", regionScope: "CAN" },
  ];
}
